```{.r .cell-code  code-summary="Which parameters appear for which event types?"}
# Heatmap-style table: parameters × event types
param_inventory |>
  filter(
    # Focus on the most analytically useful event types
    event_name %in%
      c(
        "page_view",
        "purchase",
        "add_to_cart",
        "view_item",
        "begin_checkout",
        "session_start"
      ),
    # And the most common parameters
    key %in%
      c(
        "page_location",
        "ga_session_id",
        "ga_session_number",
        "session_engaged",
        "transaction_id",
        "value",
        "currency",
        "engagement_time_msec",
        "page_referrer",
        "item_id",
        "item_name"
      )
  ) |>
  mutate(present = if_else(n_occurrences > 0, "✓", "")) |>
  select(key, event_name, present) |>
  pivot_wider(
    names_from = event_name,
    values_from = present,
    values_fill = ""
  ) |>
  gt() |>
  tab_header(
    title = "Parameter Availability by Event Type",
    subtitle = "✓ = parameter present for this event type"
  ) |>
  cols_label(key = "Parameter") |>
  opt_stylize(style = 1)
```

